$folder = "C:\CSRM"
$exeUrl = "https://dl5.oo-software.com/files/ooshutup10/OOSU10.exe"
$exePath = Join-Path $folder "OOSU10.exe"
$configPath = Join-Path $folder "oosuconfig.cfg"

# Base64-encoded content of oosuconfig.cfg
$encodedConfig = @"

"@

# Ensure folder exists
if (-not (Test-Path $folder)) {
    New-Item -ItemType Directory -Path $folder -Force | Out-Null
}

# Write config file from Base64
[System.IO.File]::WriteAllBytes($configPath, [Convert]::FromBase64String($encodedConfig))

# Download OOSU10 binary
Invoke-WebRequest -Uri $exeUrl -OutFile $exePath -UseBasicParsing

# Run it with the config silently
Start-Process -FilePath $exePath -ArgumentList "`"$configPath`" /quiet" -Wait
